import{_ as e,o as r,c as a,ai as s}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Le Präteritum","description":"","frontmatter":{},"headers":[],"relativePath":"module-4-le-temps/prateritum.md","filePath":"module-4-le-temps/prateritum.md","lastUpdated":1773298982000}'),n={name:"module-4-le-temps/prateritum.md"};function i(d,t,o,l,m,u){return r(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="le-prateritum" tabindex="-1">Le Präteritum <a class="header-anchor" href="#le-prateritum" aria-label="Permalink to “Le Präteritum”">​</a></h1><p><strong>Prérequis :</strong> <a href="./participe-passe.html">Le participe passé</a></p><p><strong>Objectif :</strong> connaître le Präteritum de sein et haben, et comprendre quand ce temps s&#39;utilisé.</p><p>Le Präteritum est le temps narratif allemand. A l&#39;oral, on lui prefere presque toujours le Perfekt - avec deux exceptions importantes qu&#39;il faut absolument maitriser.</p><h2 id="quand-utilise-t-on-le-prateritum" tabindex="-1">Quand utilisé-t-on le Präteritum ? <a class="header-anchor" href="#quand-utilise-t-on-le-prateritum" aria-label="Permalink to “Quand utilisé-t-on le Präteritum ?”">​</a></h2><div class="mt-4 grid gap-3"><div class="p-4 rounded-xl border border-orange-200 bg-orange-50"><div class="font-semibold text-orange-800">A l&#39;ecrit</div><div class="text-sm text-orange-700 mt-1">Romans, articles, rapports, narration formelle. C&#39;est le temps du recit ecrit, equivalent du passé simple français dans ce contexte.</div></div><div class="p-4 rounded-xl border border-green-200 bg-green-50"><div class="font-semibold text-green-800">A l&#39;oral : sein et haben uniquement</div><div class="text-sm text-green-700 mt-1">*War* et *hatte* sont plus naturels que *ist gewesen* et *hat gehabt* même dans la conversation courante. Ces deux formes s&#39;utilisent donc au Präteritum même a l&#39;oral.</div></div></div><div class="tip custom-block"><p class="custom-block-title">Priorité absolue : apprendre <em>war</em> et <em>hatte</em></p><p>Pour un débutant, l&#39;essentiel du Präteritum tient en deux verbes. Les autres peuvent attendre que tu lises des textes allemands.</p></div><h2 id="sein-au-prateritum" tabindex="-1">sein au Präteritum <a class="header-anchor" href="#sein-au-prateritum" aria-label="Permalink to “sein au Präteritum”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>ich</td><td><strong>war</strong></td></tr><tr><td>du</td><td><strong>warst</strong></td></tr><tr><td>er/sie/es</td><td><strong>war</strong></td></tr><tr><td>wir</td><td><strong>waren</strong></td></tr><tr><td>ihr</td><td><strong>wart</strong></td></tr><tr><td>sie/Sie</td><td><strong>waren</strong></td></tr></tbody></table><p>Exemples :</p><ul><li><em>Ich war gestern zu Hause.</em> - J&#39;etais chez moi hier.</li><li><em>Wo warst du ?</em> - Ou etais-tu ?</li><li><em>Es war kalt.</em> - Il faisait froid.</li><li><em>Wir waren in Berlin.</em> - Nous etions a Berlin.</li></ul><h2 id="haben-au-prateritum" tabindex="-1">haben au Präteritum <a class="header-anchor" href="#haben-au-prateritum" aria-label="Permalink to “haben au Präteritum”">​</a></h2><table tabindex="0"><thead><tr><th>Pronom</th><th>Forme</th></tr></thead><tbody><tr><td>ich</td><td><strong>hatte</strong></td></tr><tr><td>du</td><td><strong>hattest</strong></td></tr><tr><td>er/sie/es</td><td><strong>hatte</strong></td></tr><tr><td>wir</td><td><strong>hatten</strong></td></tr><tr><td>ihr</td><td><strong>hattet</strong></td></tr><tr><td>sie/Sie</td><td><strong>hatten</strong></td></tr></tbody></table><p>Exemples :</p><ul><li><em>Ich hatte keine Zeit.</em> - Je n&#39;avais pas le temps.</li><li><em>Er hatte Hunger.</em> - Il avait faim.</li><li><em>Wir hatten Gluck.</em> - Nous avions de la chance.</li></ul><h2 id="formation-du-prateritum-des-verbes-reguliers" tabindex="-1">Formation du Präteritum des verbes réguliers <a class="header-anchor" href="#formation-du-prateritum-des-verbes-reguliers" aria-label="Permalink to “Formation du Präteritum des verbes réguliers”">​</a></h2><p>Pour référence : radical + <em>-te</em> + terminaison.</p><table tabindex="0"><thead><tr><th>Pronom</th><th>machen</th><th>lernen</th></tr></thead><tbody><tr><td>ich</td><td>mach<strong>te</strong></td><td>lern<strong>te</strong></td></tr><tr><td>du</td><td>mach<strong>test</strong></td><td>lern<strong>test</strong></td></tr><tr><td>er/sie/es</td><td>mach<strong>te</strong></td><td>lern<strong>te</strong></td></tr><tr><td>wir</td><td>mach<strong>ten</strong></td><td>lern<strong>ten</strong></td></tr><tr><td>ihr</td><td>mach<strong>tet</strong></td><td>lern<strong>tet</strong></td></tr><tr><td>sie/Sie</td><td>mach<strong>ten</strong></td><td>lern<strong>ten</strong></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Le Präteritum des irréguliers est a part</p><p>Les verbes forts changent de voyelle radicale au Präteritum (<em>gehen → ging</em>, <em>kommen → kam</em>, <em>fahren → fuhr</em>). Ces formes s&#39;apprennent progressivement par la lecture. Pour l&#39;oral, le Perfekt reste largement prefere.</p></div>',19)])])}const c=e(n,[["render",i]]);export{p as __pageData,c as default};
